#include <vector>
class DynArray {
    int* m_data{}; int m_size{};
    static inline int s_moves{0};
public:
    DynArray() = default;
    DynArray(int size): m_data{ size>0?new int[size]{}:nullptr }, m_size{size} {}
    DynArray(DynArray&& src) noexcept : m_data{src.m_data}, m_size{src.m_size}{ ++s_moves; src.m_data=nullptr; src.m_size=0; }
    DynArray& operator=(DynArray&& src) noexcept {
        if(this!=&src){ ++s_moves; delete[] m_data; m_data=src.m_data; m_size=src.m_size; src.m_data=nullptr; src.m_size=0; }
        return *this;
    }
    ~DynArray(){ delete[] m_data; }
    DynArray(const DynArray&)=delete;
    DynArray& operator=(const DynArray&)=delete;
    int size() const { return m_size; }
    static int moves(){ return s_moves; }
};
class Holder {
    std::vector<DynArray> m_items;
public:
    void reserve(int n){ m_items.reserve(n); }
    void load(DynArray&& a){ m_items.push_back(std::move(a)); }
    int count() const { return (int)m_items.size(); }
    int total() const { int t=0; for(const auto& it:m_items) t+=it.size(); return t; }
};
int main(){
    int q{}; std::cin >> q;
    Holder h; h.reserve(q);
    for(int i=0;i<q;++i){
        std::string cmd; std::cin >> cmd;
        if(cmd=="load"){
            int size; std::cin >> size;
            DynArray src{ size };
            int before = src.size();
            h.load(std::move(src));
            std::cout << "load " << before << " source " << src.size() << '\n';
        } else if(cmd=="report"){
            std::cout << "holder count " << h.count() << " total " << h.total() << " moves " << DynArray::moves() << '\n';
        }
    }
    return 0;
}

